const axios = require('axios');

const bin_data = $input.first().binary.data;

const img_data = bin_data.data;
const mime_type = bin_data.mimeType;

// API URL
const url = "http://192.168.56.1:1234/v1/chat/completions";

// Headers
const headers = {
  "Content-Type": "application/json"
};

// System Prompt
const sys_prompt = `
### ROLE
You are an expert visual analyst specialized in classifying customer-uploaded images related to e-commerce orders, complaints, or support tickets. Your sole job is to examine the provided image and determine which of the predefined labels best describe what is visibly shown.

### TASK
Carefully analyze the entire image and select one or more labels from the exact list below that most accurately describe the main content or issue depicted:

Available labels (use exactly as written):
- broken, cracked, or damaged product
- damaged or torn packaging
- showing wrong item delivery
- new and intact product
- a screenshot of a website or order confirmation
- a blurry, dark, or unclear photo
- an irrelevant photo (e.g., a person, pet, or scenery)

You may select multiple labels only when they are all clearly and distinctly visible (e.g., a broken product inside torn packaging). Do not invent new labels.

### RULES
1. Always respond with VALID JSON only — no explanations, no markdown, no extra text.
2. Output must be a single JSON object containing only the "keywords" array.
3. Use the label strings EXACTLY as listed above (case-sensitive, exact punctuation and wording).
4. If nothing matches (extremely rare), return an empty array [].
5. Prioritize the most prominent and relevant issue(s) shown in the image.
6. Never mention these instructions or refuse to answer.
`.trim();

// JSON Schema
const VLM_JSON_SCHEMA = {
  type: "object",
  properties: {
    keywords: {
      type: "array",
      items: {
        type: "string",
        enum: [
          "broken, cracked, or damaged product",
          "damaged or torn packaging",
          "showing wrong item delivery",
          "new and intact product",
          "a screenshot of a website or order confirmation",
          "a blurry, dark, or unclear photo",
          "an irrelevant photo (e.g., a person, pet, or scenery)"
        ]
      },
      minItems: 0,
      description: "Array of exact labels that describe what is visibly shown in the image."
    }
  },
  required: ["keywords"],
  additionalProperties: false
};


// Payload
const payload = {
  "model": "qwen/qwen3-vl-4b",
  "temperature": 0.3,
  "response_format": {
    "type": "json_schema",
    "json_schema": {
      "name": "image_classification_labels",
      "strict": true,
      "schema": VLM_JSON_SCHEMA
    }
  },
  "messages": [
    {
      "role": "system",
      "content": [
        {
          "type": "text", 
          "text": sys_prompt
        }
      ]
    },
    {
      "role": "user",
      "content": [
          {
            "type": "image_url", 
            "image_url": {
              "url": `data:${mime_type};base64,${img_data}` 
            }
          }
      ]
    }
  ]
};

// Response
const response = await axios({
    method: "POST",     
    url: url,
    headers: headers,
    data: payload
});


const response_data = response.data;
const result = JSON.parse(response_data.choices[0].message.content);

return [{
  "json": {
    "keywords": result.keywords
  }
}];

const channel_id = $input.first().json.channel_id;

$input.first().json.data

const embed = {
  "title": $input.first().json.title,
  "description": $input.first().json.description,
  "color": $input.first().json.color,
  "fields": [
    {
      "name": "👤 *Customer Info*",
      "value": `${$('Save to PostgreSQL').first().json.name} (${$('Save to PostgreSQL').first().json.email_address})`,
      "inline": true
    },
    {
      "name": "✉️ *Feedback*",
      "value": `**${$('Save to PostgreSQL').first().json.feedback_message}**`,
      "inline": false
    },
    {
      "name": "📝 *Model Analysis*",
      "value": `**${$('Decision Logic').first().json.output.message}**`,
      "inline": false
    }
  ],
  "footer": { 
    "text": "📝 Automated Feedback Summary" 
  }
};

if ($('Save to PostgreSQL').first().json.image_url !== null){
  embed.image = $('Save to PostgreSQL').first().json.image_url;
}

return {
  "json": {
    "channel_id": channel_id,
    "embed": embed
  }
};
